def test_in_place_subtractor_modulo_n():
    # 1-bit: a=[0], b=[1], ancilla=2 → width 3.  After: a unchanged, b := (b - a) mod 2 = b XOR a.
    for a_val in range(2):
        for b_val in range(2):
            qc = QuantumCircuit(3)
            if a_val: qc.x(0)
            if b_val: qc.x(1)
            qc = in_place_subtractor_modulo_n(qc, [0], [1])
            sv = Statevector.from_instruction(qc).data
            diff = (b_val - a_val) % 2
            expected_idx = a_val | (diff << 1)  # ancilla must return to 0
            assert np.isclose(np.abs(sv[expected_idx]), 1.0, atol=1e-9), (
                f"1-bit a={a_val} b={b_val}: expected (b-a)%2={diff}"
            )

    # 2-bit: a=[0,1], b=[2,3], ancilla=4 → width 5.  Check full sweep.
    for a_val in range(4):
        for b_val in range(4):
            qc = QuantumCircuit(5)
            if a_val & 1: qc.x(0)
            if a_val & 2: qc.x(1)
            if b_val & 1: qc.x(2)
            if b_val & 2: qc.x(3)
            qc = in_place_subtractor_modulo_n(qc, [0, 1], [2, 3])
            sv = Statevector.from_instruction(qc).data
            diff = (b_val - a_val) % 4
            expected_idx = a_val | ((diff & 1) << 2) | ((diff & 2) << 2)
