from qiskit import QuantumCircuit
from typing import List

def verify_total_weight_constraint(qc: QuantumCircuit, weights: List[int], selection: List[int], weight_reg: List[int], capacity: int, target: int) -> QuantumCircuit:
    """
    Verify that selected items' total weight <= capacity.

    Args:
        qc: Quantum circuit to modify
        weights: List of item weights
        selection: List of selection qubit indices
        weight_reg: List of weight register qubit indices
        capacity: Maximum allowed weight
        target: Target qubit to flip if constraint satisfied

    Returns:
        Modified quantum circuit
    """
    n = len(weight_reg)

    # Add weights to register
    for i, weight in enumerate(weights):
        for bit_pos in range(n):
            if (weight >> bit_pos) & 1:
                qc.cx(selection[i], weight_reg[bit_pos])

    # Check if weight_reg <= capacity
    max_val = 2 ** n
    for val in range(min(capacity + 1, max_val)):
        pattern = [(val >> j) & 1 == 1 for j in range(n)]
        for j, bit in enumerate(pattern):
            if not bit:
                qc.x(weight_reg[j])
        if len(weight_reg) == 1:
            qc.cx(weight_reg[0], target)
        elif len(weight_reg) == 2:
            qc.ccx(weight_reg[0], weight_reg[1], target)
        else:
            qc.mcx(weight_reg, target)
        for j, bit in enumerate(pattern):
            if not bit:
                qc.x(weight_reg[j])

    # Uncompute weight calculation
    for i, weight in enumerate(weights):
        for bit_pos in range(n):
            if (weight >> bit_pos) & 1:
                qc.cx(selection[i], weight_reg[bit_pos])

    return qc

