from qiskit import QuantumCircuit
from typing import List
from itertools import product

def verify_bounded_profit_constraint(qc: QuantumCircuit, profits: List[int], jagged: List[List[int]], min_profit: int, target: int) -> QuantumCircuit:
    """
    Verify bounded knapsack profit constraint.

    Args:
        qc: Quantum circuit to modify
        profits: List of item profits
        jagged: Jagged array of quantity qubit indices
        min_profit: Minimum required profit
        target: Target qubit to flip if satisfied

    Returns:
        Modified quantum circuit
    """
    limits = [2**len(q) - 1 for q in jagged]

    # Mark valid combinations (profit >= min_profit)
    ranges = [range(l + 1) for l in limits]
    for combo in product(*ranges):
        total_profit = sum(p * q for p, q in zip(profits, combo))
        if total_profit >= min_profit:
            all_qubits = []
            for item_idx, qty in enumerate(combo):
                for bit_idx, q in enumerate(jagged[item_idx]):
                    if not ((qty >> bit_idx) & 1):
                        qc.x(q)
                    all_qubits.append(q)

            if len(all_qubits) == 1:
                qc.cx(all_qubits[0], target)
            elif len(all_qubits) == 2:
                qc.ccx(all_qubits[0], all_qubits[1], target)
            elif len(all_qubits) > 2:
                qc.mcx(all_qubits, target)

            for item_idx, qty in enumerate(combo):
                for bit_idx, q in enumerate(jagged[item_idx]):
                    if not ((qty >> bit_idx) & 1):
                        qc.x(q)

    return qc

from qiskit import QuantumCircuit, QuantumRegister
from typing import List, Tuple

def oracle_sat(qc: QuantumCircuit, query_qubits: list[int], target: int,
              problem: List[List[Tuple[int, bool]]]) -> QuantumCircuit:
    """
    General SAT oracle: evaluates a complete SAT formula.

    Args:
        qc: Quantum circuit to modify
        query_qubits: List of input qubit indices
        target: Target qubit index
        problem: List of clauses, each clause is list of (variable_index, is_positive) tuples

    Returns:
        Modified quantum circuit
    """
    if not problem:
        return qc

    num_clauses = len(problem)

    # Create auxiliary qubits to store clause results
    max_qubit = max(query_qubits + [target])
    aux_qubits = list(range(max_qubit + 1, max_qubit + 1 + num_clauses))

    # Add auxiliary qubits to circuit
    while qc.num_qubits < max(aux_qubits) + 1:
        qc.add_register(QuantumRegister(1))

    # Evaluate each clause and store result in auxiliary qubit
    for i, clause in enumerate(problem):
        if not clause:
            continue

        # Get qubits and flip flags for this clause
        clause_qubits = [query_qubits[var_idx] for var_idx, _ in clause]
        flips_needed = [not is_positive for _, is_positive in clause]

        # Flip qubits that appear negated
        for j, needs_flip in enumerate(flips_needed):
            if needs_flip:
                qc.x(clause_qubits[j])

        # Apply OR logic: A ∨ B = ¬(¬A ∧ ¬B)
        for qubit in clause_qubits:
            qc.x(qubit)

        # Multi-controlled NOT for AND of negated variables
        if len(clause_qubits) == 1:
            qc.cx(clause_qubits[0], aux_qubits[i])
        elif len(clause_qubits) == 2:
            qc.ccx(clause_qubits[0], clause_qubits[1], aux_qubits[i])
        else:
            qc.mcx(clause_qubits, aux_qubits[i])

        # Restore clause qubits
        for qubit in clause_qubits:
            qc.x(qubit)

        # Final negation for OR
        qc.x(aux_qubits[i])

        # Restore original negated variables
        for j, needs_flip in enumerate(flips_needed):
            if needs_flip:
                qc.x(clause_qubits[j])

    # AND all clause results together
    if num_clauses == 1:
        qc.cx(aux_qubits[0], target)
    elif num_clauses == 2:
        qc.ccx(aux_qubits[0], aux_qubits[1], target)
    else:
        qc.mcx(aux_qubits, target)

    # Uncompute auxiliary qubits
    for i, clause in enumerate(problem):
        if not clause:
            continue

        clause_qubits = [query_qubits[var_idx] for var_idx, _ in clause]
        flips_needed = [not is_positive for _, is_positive in clause]

        for j, needs_flip in enumerate(flips_needed):
            if needs_flip:
                qc.x(clause_qubits[j])

        qc.x(aux_qubits[i])

        for qubit in clause_qubits:
            qc.x(qubit)

        if len(clause_qubits) == 1:
            qc.cx(clause_qubits[0], aux_qubits[i])
        elif len(clause_qubits) == 2:
            qc.ccx(clause_qubits[0], clause_qubits[1], aux_qubits[i])
        else:
            qc.mcx(clause_qubits, aux_qubits[i])

        for qubit in clause_qubits:
            qc.x(qubit)

        for j, needs_flip in enumerate(flips_needed):
            if needs_flip:
                qc.x(clause_qubits[j])

    return qc

class TruthTable:
    def __init__(self, bits: int, num_vars: int):
        self.bits = bits
        self.num_vars = num_vars

    def __eq__(self, other):
        return self.bits == other.bits and self.num_vars == other.num_vars

def projective_truth_tables() -> tuple[TruthTable, TruthTable, TruthTable]:
    """
    Return the three projective functions x₁, x₂, x₃.

    Returns:
        Tuple of (x1, x2, x3) truth tables
    """
    x1 = TruthTable(0b10101010, 3)  # x₁ is true when least significant bit is 1
    x2 = TruthTable(0b11001100, 3)  # x₂ is true when second bit is 1 (assignments 010, 011, 110, 111)
    x3 = TruthTable(0b11110000, 3)  # x₃ is true when most significant bit is 1 (assignments 100-111)

    return (x1, x2, x3)

