    0: [],
    1: [("H", 0), ("H", 1)],
    2: [("H", 0), ("CX", (0, 1)), ("H", 0)],
}
_COL_CIRCUITS = {
    0: [("H", 0)],
    1: [("H", 1)],
    2: [("CX", (0, 1)), ("H", 0)],
}
_ROW_DECODE = {
    0: [(0, +1), (1, +1), (2, +1)],
    1: [(1, +1), (0, +1), (2, +1)],
    2: [(0, -1), (1, -1), (2, +1)],
}
_COL_DECODE = {
