}

def _zval(idx, m0, m1):
    return [(-1) ** m1, (-1) ** m0, (-1) ** (m0 ^ m1)][idx]

def _apply(qc, ops, qs):
    for name, arg in ops:
        if name == "H":
            qc.h(qs[arg])
        elif name == "CX":
            qc.cx(qs[arg[0]], qs[arg[1]])

