        cbit1 = qc.num_clbits; qc.add_register(ClassicalRegister(1)); qc.measure(qs[1], cbit1)
        decode_spec = _ROW_DECODE[row_index]
        def dec(m0, m1): return [s * _zval(i, m0, m1) for i, s in decode_spec]
