from qiskit import QuantumCircuit, ClassicalRegister
from qiskit_aer import AerSimulator

def valid_alice_move(cells: list[int]) -> bool:
    if any(v not in (-1, 1) for v in cells):
        return False
    return sum(1 for v in cells if v == -1) % 2 == 0

def valid_bob_move(cells: list[int]) -> bool:
    if any(v not in (-1, 1) for v in cells):
        return False
    return sum(1 for v in cells if v == -1) % 2 == 1

def win_condition(row_index: int, column_index: int, row: list[int], column: list[int]) -> bool:
    if not valid_alice_move(row) or not valid_bob_move(column):
        return False
    return row[column_index] == column[row_index]

def alice_classical(row_index: int) -> list[int]:
    strategies = [
        [1, 1, 1],
        [1, -1, -1],
        [-1, 1, -1],
    ]
    return strategies[row_index]

def bob_classical(column_index: int) -> list[int]:
    strategies = [
        [1, 1, -1],
        [1, -1, 1],
        [-1, -1, -1],
    ]
    return strategies[column_index]

# --- Peres magic-square quantum protocol (same as 2.6/2.7) ---

_ROW_CIRCUITS = {
    0: [],
    1: [("H", 0), ("H", 1)],
    2: [("H", 0), ("CX", (0, 1)), ("H", 0)],
}
_COL_CIRCUITS = {
    0: [("H", 0)],
    1: [("H", 1)],
    2: [("CX", (0, 1)), ("H", 0)],
}
_ROW_DECODE = {
    0: [(0, +1), (1, +1), (2, +1)],
    1: [(1, +1), (0, +1), (2, +1)],
    2: [(0, -1), (1, -1), (2, +1)],
}
_COL_DECODE = {
    0: [(0, +1), (1, +1), (2, -1)],
    1: [(1, +1), (0, +1), (2, -1)],
    2: [(0, +1), (1, +1), (2, -1)],
}

def _zval(idx, m0, m1):
    return [(-1) ** m1, (-1) ** m0, (-1) ** (m0 ^ m1)][idx]

def _apply(qc, ops, qs):
    for name, arg in ops:
        if name == "H":
            qc.h(qs[arg])
        elif name == "CX":
            qc.cx(qs[arg[0]], qs[arg[1]])

def _play_one_quantum_round(row_index: int, column_index: int):
    qc = QuantumCircuit(4)
    # Two Bell pairs: (alice q0 <-> bob q0) = (0, 2); (alice q1 <-> bob q1) = (1, 3)
    qc.h(0); qc.cx(0, 2)
    qc.h(1); qc.cx(1, 3)
    # Alice's basis rotation on qubits [0, 1]
    _apply(qc, _ROW_CIRCUITS[row_index], [0, 1])
    # Bob's basis rotation on qubits [2, 3]
    _apply(qc, _COL_CIRCUITS[column_index], [2, 3])
    qc.add_register(ClassicalRegister(4))
    qc.measure([0, 1, 2, 3], [0, 1, 2, 3])
    counts = AerSimulator().run(qc, shots=1).result().get_counts()
    bits = list(counts.keys())[0].replace(" ", "")
    a_m0 = int(bits[-1]); a_m1 = int(bits[-2])
    b_m0 = int(bits[-3]); b_m1 = int(bits[-4])
    alice_row = [sgn * _zval(idx, a_m0, a_m1) for idx, sgn in _ROW_DECODE[row_index]]
    bob_col = [sgn * _zval(idx, b_m0, b_m1) for idx, sgn in _COL_DECODE[column_index]]
    return alice_row, bob_col

def test_magic_square_strategies() -> dict:
    """
    Test both classical and quantum magic-square strategies by actually playing
    each over all 9 (row, column) input combinations, with several trials per
    combination for the quantum side.
    """
    results = {
        "classical_wins": 0,
        "classical_total": 0,
        "classical_win_rate": 0.0,
        "quantum_wins": 0,
        "quantum_total": 0,
        "quantum_win_rate": 0.0,
        "game_results": [],
    }

    for row_idx in range(3):
        for col_idx in range(3):
            # Classical
            a_move = alice_classical(row_idx)
            b_move = bob_classical(col_idx)
            won = win_condition(row_idx, col_idx, a_move, b_move)
            results["classical_total"] += 1
            if won:
                results["classical_wins"] += 1
            results["game_results"].append({
                "row": row_idx, "col": col_idx,
                "alice_move": a_move, "bob_move": b_move,
                "won": won, "strategy": "classical",
            })

            # Quantum: 5 independent rounds per (row, col)
            for _ in range(5):
                a_row, b_col = _play_one_quantum_round(row_idx, col_idx)
                q_won = win_condition(row_idx, col_idx, a_row, b_col)
                results["quantum_total"] += 1
                if q_won:
                    results["quantum_wins"] += 1
                results["game_results"].append({
                    "row": row_idx, "col": col_idx,
                    "alice_move": a_row, "bob_move": b_col,
                    "won": q_won, "strategy": "quantum",
                })

    results["classical_win_rate"] = results["classical_wins"] / results["classical_total"]
    results["quantum_win_rate"] = results["quantum_wins"] / results["quantum_total"]
    return results

